def is_var(x):
    return isinstance(x, str) and x.startswith("?")


def lookup(x, env):
    while is_var(x) and x in env:
        x = env[x]
    return x


def bind(expr, env):
    expr = lookup(expr, env)
    if isinstance(expr, list):
        return [bind(part, env) for part in expr]
    return expr


def unify(e, f, env):
    e = lookup(e, env)
    f = lookup(f, env)
    if e == f:
        return True
    if is_var(e):
        env[e] = f
        return True
    if is_var(f):
        env[f] = e
        return True
    if not isinstance(e, list) or not isinstance(f, list):
        return False
    if len(e) != len(f):
        return False
    for i in range(len(e)):
        if not unify(e[i], f[i], env):
            return False
    return True


def rename_variables(expr, n):
    if is_var(expr):
        return expr + "_" + str(n)
    if isinstance(expr, list):
        return [rename_variables(part, n) for part in expr]
    return expr

def classify(token):
    if isinstance(token, str) and token.startswith("?"):
        return "variable"
    if isinstance(token, list):
        return "list"
    return "atom"

def match_element(pattern_part, expression_part, bindings):
    if is_var(pattern_part):
        if pattern_part in bindings:
            return bindings[pattern_part] == expression_part
        bindings[pattern_part] = expression_part
        return True
    return pattern_part == expression_part

def match_pattern(pattern, expression):
    if len(pattern) != len(expression):
        return None
    bindings = {}
    for i in range(len(pattern)):
        if not match_element(pattern[i], expression[i], bindings):
            return None
    return bindings

def lookup_value(name, env):
    while is_var(name) and name in env:
        name = env[name]
    return name

def occurs(var, expr):
    if expr == var:
        return True
    if isinstance(expr, list):
        for part in expr:
            if occurs(var, part):
                return True
    return False

def unify_lists(e, f, env):
